 82	func dirtyWorktreePaths(dir string) []string {
 83		out, err := internalgit.Command(context.Background(), dir, "status", "--porcelain", "--untracked-files=all").Output()
 84		if err != nil {
 85			return nil
 86		}
 87		var paths []string
 88		seen := map[string]bool{}
 89		for _, line := range strings.Split(string(out), "\n") {
 90			line = strings.TrimRight(line, "\r")
 91			if strings.TrimSpace(line) == "" || len(line) < 4 {
 92				continue
 93			}
 94			path := strings.TrimSpace(line[3:])
 95			if idx := strings.Index(path, " -> "); idx >= 0 {
 96				path = strings.TrimSpace(path[idx+4:])
 97			}
 98			if path == "" || seen[path] {
 99				continue
100			}
101			seen[path] = true
102			paths = append(paths, path)
103		}
104		return paths
105	}
