145	// SynthesizeCommit stages real file changes, explicitly excluding harness noise
146	// paths, and creates a commit with msg as the commit message. Returns (true, nil)
147	// when a commit was made, (false, nil) when nothing real remained to commit
148	// after exclusions, and (false, err) on failure.
149	func (r *RealGitOps) SynthesizeCommit(dir, msg string) (bool, error) {
150		// Do NOT list already-gitignored paths (.ddx/agent-logs, .ddx/workers) as
151		// :(exclude) pathspecs. Git treats a path named by :(exclude) as explicitly
152		// referenced, so when the path is also .gitignored git emits "The following
153		// paths are ignored by one of your .gitignore files" AND exits 1 — even
154		// though the pathspec is trying to SKIP it. Paths already in .gitignore are
155		// excluded by default; excludes here are only for paths that would
156		// otherwise be tracked.
157		addArgs := []string{
158			"add", "-A", "--",
159			".",
160		}
161		addArgs = append(addArgs, synthesizeCommitExcludePathspecs(dir)...)
162		if err := internalgit.Command(context.Background(), dir, addArgs...).Run(); err != nil {
163			return false, fmt.Errorf("staging changes: %w", err)
164		}
165		statusOut, _ := internalgit.Command(context.Background(), dir, "diff", "--cached", "--name-only").Output()
166		if len(bytes.TrimSpace(statusOut)) == 0 {
167			return false, nil
168		}
169		if msg == "" {
170			msg = "chore: execute-bead synthesized result commit"
171		}
172		out, err := internalgit.Command(context.Background(), dir, "commit", "-m", msg).CombinedOutput()
173		if err != nil {
174			return false, fmt.Errorf("synthesize commit: %s: %w", strings.TrimSpace(string(out)), err)
175		}
176		return true, nil
177	}
