 12		"github.com/DocumentDrivenDX/ddx/internal/config"
 13		internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
 14	)
 15	
 16	const preDispatchCheckpointDirtyRefusalPrefix = "checkpoint refused to absorb implementation changes outside DDx bookkeeping: "
 17	const preDispatchDirtyPreserveRefPrefix = "refs/ddx/pre-dispatch/"
 18	
 19	// PreDispatchDirtyPreservation records the recoverable handle DDx created when
 20	// it preserved implementation dirt before a watch-mode redispatch.
 21	type PreDispatchDirtyPreservation struct {
 22		DirtyPaths     []string
 23		PreserveRef    string
 24		RecoverCommand string
 25	}
 26	
 27	var preDispatchDirtyPathLister = func(projectRoot string) ([]string, error) {
 28		return preDispatchCheckpointDirtyPaths(projectRoot)
 29	}
 30	
 31	func normalizePreDispatchDirtyPaths(paths []string) []string {
 32		seen := make(map[string]bool, len(paths))
 33		normalized := make([]string, 0, len(paths))
 34		for _, path := range paths {
 35			path = filepath.ToSlash(strings.TrimSpace(path))
 36			if path == "" || seen[path] {
 37				continue
 38			}
 39			seen[path] = true
 40			normalized = append(normalized, path)
 41		}
 42		sort.Strings(normalized)
 43		return normalized
 44	}
 45	
 46	func intersectPreDispatchDirtyPaths(current, want []string) []string {
 47		if len(current) == 0 || len(want) == 0 {
 48			return nil
 49		}
 50		wantSet := make(map[string]bool, len(want))
 51		for _, path := range want {
 52			wantSet[path] = true
 53		}
 54		var overlap []string
 55		for _, path := range current {
 56			if wantSet[path] {
 57				overlap = append(overlap, path)
 58			}
 59		}
 60		sort.Strings(overlap)
 61		return overlap
 62	}
 63	
 64	func classifyPreDispatchDirtyPaths(dirtyPaths []string) (allowedPaths, blockedPaths []string) {
 65		for _, path := range normalizePreDispatchDirtyPaths(dirtyPaths) {
 66			if preDispatchCheckpointAllowedPath(path) {
 67				allowedPaths = append(allowedPaths, path)
 68				continue
 69			}
 70			blockedPaths = append(blockedPaths, path)
 71		}
 72		return allowedPaths, blockedPaths
 73	}
 74	
 75	// stablePreDispatchImplementationDirtyPaths re-reads the project dirt and only
 76	// treats implementation paths as actionable when they survive the immediate
 77	// recheck. This filters transient rename/delete paths that can briefly appear
 78	// in watch mode right after a successful land.
 79	func stablePreDispatchImplementationDirtyPaths(projectRoot string, dirtyPaths []string) ([]string, []string, error) {
 80		normalized := normalizePreDispatchDirtyPaths(dirtyPaths)
 81		if projectRoot == "" || len(normalized) == 0 {
 82			return normalized, normalized, nil
 83		}
 84	
 85		currentPaths, err := preDispatchDirtyPathLister(projectRoot)
 86		if err != nil {
 87			return nil, nil, fmt.Errorf("rechecking pre-dispatch dirt: %w", err)
 88		}
 89		return intersectPreDispatchDirtyPaths(currentPaths, normalized), currentPaths, nil
 90	}
 91	
 92	func resolveOptionalGitRef(dir, ref string) (string, bool) {
 93		out, err := internalgit.Command(context.Background(), dir, "rev-parse", "-q", "--verify", ref).Output()
 94		if err != nil {
 95			return "", false
 96		}
 97		sha := strings.TrimSpace(string(out))
 98		if sha == "" {
 99			return "", false
100		}
101		return sha, true
102	}
103	
104	func preDispatchDirtyRecoverCommand(preserveRef string) string {
105		if preserveRef == "" {
106			return ""
107		}
108		return "git stash apply " + preserveRef
109	}
110	
111	func preservePreDispatchDirtyPaths(projectRoot string, dirtyPaths []string) (*PreDispatchDirtyPreservation, error) {
112		if projectRoot == "" {
113			return nil, fmt.Errorf("project root is required for pre-dispatch dirty preservation")
114		}
115		normalized := normalizePreDispatchDirtyPaths(dirtyPaths)
116		if len(normalized) == 0 {
117			return nil, fmt.Errorf("no dirty implementation paths to preserve")
118		}
119	
120		var preserved *PreDispatchDirtyPreservation
121		if err := withTrackerLock(projectRoot, "preserve_dirt", func() error {
122			var err error
123			preserved, err = preservePreDispatchDirtyPathsLocked(projectRoot, normalized)
124			return err
125		}); err != nil {
126			return nil, err
127		}
128		return preserved, nil
129	}
130	
131	func preservePreDispatchDirtyPathsLocked(projectRoot string, dirtyPaths []string) (*PreDispatchDirtyPreservation, error) {
132		if err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Run(); err != nil {
133			return nil, fmt.Errorf("verifying project worktree for pre-dispatch preservation: %w", err)
134		}
135		if out, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", "HEAD").CombinedOutput(); err != nil {
136			return nil, fmt.Errorf("resolving HEAD for pre-dispatch preservation: %s: %w", strings.TrimSpace(string(out)), err)
137		}
138	
139		stashBefore, _ := resolveOptionalGitRef(projectRoot, "refs/stash")
140		preserveID := GenerateAttemptID()
141		preserveRef := preDispatchDirtyPreserveRefPrefix + preserveID
142		stashMsg := "ddx pre-dispatch preserve " + preserveID
143		stashArgs := []string{"stash", "push", "--include-untracked", "--message", stashMsg, "--"}
144		stashArgs = append(stashArgs, dirtyPaths...)
145		if out, err := internalgit.Command(context.Background(), projectRoot, stashArgs...).CombinedOutput(); err != nil {
146			return nil, fmt.Errorf("preserving pre-dispatch dirty implementation paths: %s: %w", strings.TrimSpace(string(out)), err)
147		}
148	
149		stashAfter, ok := resolveOptionalGitRef(projectRoot, "refs/stash")
150		if !ok || stashAfter == "" || stashAfter == stashBefore {
151			return nil, fmt.Errorf("preserving pre-dispatch dirty implementation paths did not create a recoverable stash entry")
152		}
153		if out, err := internalgit.Command(context.Background(), projectRoot, "update-ref", preserveRef, stashAfter).CombinedOutput(); err != nil {
154			return nil, fmt.Errorf("pinning pre-dispatch dirty preservation ref: %s: %w", strings.TrimSpace(string(out)), err)
155		}
156		_, _ = internalgit.Command(context.Background(), projectRoot, "stash", "drop", "stash@{0}").CombinedOutput()
157	
158		remainingPaths, err := preDispatchDirtyPathLister(projectRoot)
159		if err != nil {
160			return nil, fmt.Errorf("verifying preserved pre-dispatch dirt: %w", err)
161		}
162		if overlap := intersectPreDispatchDirtyPaths(remainingPaths, dirtyPaths); len(overlap) > 0 {
163			return nil, fmt.Errorf("preserving pre-dispatch dirty implementation paths left the project worktree dirty: %s", strings.Join(overlap, ", "))
164		}
165	
166		return &PreDispatchDirtyPreservation{
167			DirtyPaths:     append([]string(nil), dirtyPaths...),
168			PreserveRef:    preserveRef,
169			RecoverCommand: preDispatchDirtyRecoverCommand(preserveRef),
170		}, nil
171	}
