173	func checkpointPreDispatchDirt(projectRoot, attemptID string) (bool, error) {
174		if err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Run(); err != nil {
175			return false, nil
176		}
177		headOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", "HEAD").Output()
178		if err != nil {
179			return false, nil
180		}
181		head := strings.TrimSpace(string(headOut))
182		if head == "" {
183			return false, nil
184		}
185	
186		skipWorktreePaths, err := checkpointSkipWorktreePaths(projectRoot)
187		if err != nil {
188			return false, err
189		}
190	
191		dirtyPaths, err := preDispatchDirtyPathLister(projectRoot)
192		if err != nil {
193			return false, err
194		}
195		if len(dirtyPaths) == 0 {
196			return false, nil
197		}
198	
199		allowedPaths, blockedPaths := classifyPreDispatchDirtyPaths(dirtyPaths)
200		if len(blockedPaths) > 0 {
201			stableBlockedPaths, currentDirtyPaths, err := stablePreDispatchImplementationDirtyPaths(projectRoot, blockedPaths)
202			if err != nil {
203				return false, err
204			}
205			if len(stableBlockedPaths) > 0 {
206				return false, fmt.Errorf(
207					"%s%s; commit or clean those files before rerunning so the bead's [ddx-<id>] substantive commit stays intentional",
208					preDispatchCheckpointDirtyRefusalPrefix,
209					strings.Join(stableBlockedPaths, ", "),
210				)
211			}
212			allowedPaths, _ = classifyPreDispatchDirtyPaths(currentDirtyPaths)
213		}
214		if len(allowedPaths) == 0 {
215			return false, nil
216		}
217	
218		indexFile, err := config.CreateExecutionScratch(projectRoot, "ddx-pre-dispatch-index-*")
219		if err != nil {
220			return false, fmt.Errorf("creating temp checkpoint index: %w", err)
221		}
222		indexPath := indexFile.Name()
223		_ = indexFile.Close()
224		_ = os.Remove(indexPath)
225		defer func() { _ = os.Remove(indexPath) }()
226	
227		gitWithIndex := func(args ...string) ([]byte, error) {
228			cmd := internalgit.Command(context.Background(), projectRoot, args...)
229			cmd.Env = append(cmd.Env, "GIT_INDEX_FILE="+indexPath)
230			return cmd.CombinedOutput()
231		}
232	
233		if out, err := gitWithIndex("read-tree", "HEAD"); err != nil {
234			return false, fmt.Errorf("initializing checkpoint index: %s: %w", strings.TrimSpace(string(out)), err)
235		}
236	
237		addArgs := []string{"add", "-A", "--force", "--"}
238		addArgs = append(addArgs, allowedPaths...)
239		if out, err := gitWithIndex(addArgs...); err != nil {
240			return false, fmt.Errorf("staging checkpoint changes: %s: %w", strings.TrimSpace(string(out)), err)
241		}
242	
243		changedOut, err := gitWithIndex("diff", "--cached", "--name-only")
244		if err != nil {
245			return false, fmt.Errorf("checking checkpoint diff: %w", err)
246		}
247		if len(bytes.TrimSpace(changedOut)) == 0 {
248			return false, nil
249		}
250	
251		treeOut, err := gitWithIndex("write-tree")
252		if err != nil {
253			return false, fmt.Errorf("writing checkpoint tree: %s: %w", strings.TrimSpace(string(treeOut)), err)
254		}
255		tree := strings.TrimSpace(string(treeOut))
256		msg := "chore: checkpoint pre-execute-bead " + attemptID
257		commitOut, err := internalgit.Command(context.Background(), projectRoot,
258			"-c", "user.name=ddx-checkpoint",
259			"-c", "user.email=checkpoint@ddx.local",
260			"commit-tree", tree, "-p", head, "-m", msg,
